+        let ns_attacker = TenantNamespace::new("rogue-actor").unwrap();
+
+        // Step 1: Normal operation — legit team accesses their connector
+        engine.namespace_registry_mut().bind(
+            NamespacedResourceKind::Connector,
+            "payment-api",
+            ns_legit.clone(),
